python3 << 'PYEOF'
import csv, sys
csv.field_size_limit(sys.maxsize)
with open('market.csv') as f:
    reader = csv.DictReader(f)
    # Count resolved per resolution date
    resolved_dates = {}
    active_dates = {}
    for r in reader:
        rd = r['resolution_date']
        if r['is_resolved'] == 'True':
            resolved_dates[rd] = resolved_dates.get(rd, 0) + 1
        else:
            active_dates[rd] = active_dates.get(rd, 0) + 1

    print("Resolved count by resolution date:")
    for rd in sorted(resolved_dates):
        print(f"  {rd}: {resolved_dates[rd]}")
    print("\nActive count by resolution date:")
    for rd in sorted(active_dates):
        print(f"  {rd}: {active_dates[rd]}")
PYEOF

